using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

std::string getDllPath();

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // Create a new document
    Ptr docs = app->documents();
    if (!docs)
        return false;

    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    // Get the root component of the active design
    Ptr design = app->activeProduct();
    if (!design)
        return false;

    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a new component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    Ptr transfrom = Matrix3D::create();
    if (!transfrom)
        return false;

    Ptr occ = occs->addNewComponent(transfrom);
    if (!occ)
        return false;

    // Insert a mesh body in the sub Component
    Ptr subComp = occ->component();
    if (!subComp)
        return false;

    Ptr meshBodies = subComp->meshBodies();
    if (!meshBodies)
        return false;

     std::string stlFilePath = getDllPath() + "/" + "APIMeshFacetColors.stl";

    Ptr meshBodyList = meshBodies->add(stlFilePath, MeshUnits::InchMeshUnit);
    if (!meshBodyList)
        return false;

    Ptr stlMeshBody = meshBodyList->item(0);
    if (!stlMeshBody)
        return false;

    Ptr meshBodyProxy = stlMeshBody->createForAssemblyContext(occ);
    if (!meshBodyProxy)
        return false;

    // Get and set mesh body name
    bool isSetNameTrue = stlMeshBody->name("NewName");

    std::string newName = stlMeshBody->name();

    // Get and set mesh body selectable
    bool isSetSelectableTrue = stlMeshBody->isSelectable(false);

    bool isSelectable = stlMeshBody->isSelectable();

    isSetSelectableTrue = stlMeshBody->isSelectable(true);

    isSelectable = stlMeshBody->isSelectable();

    // Get and set Mesh body bulb light and visibility
    bool isSetBulbTrue = stlMeshBody->isLightBulbOn(false);

    bool isLightBulbOn = stlMeshBody->isLightBulbOn();

    bool isVisible = stlMeshBody->isVisible();

    isSetBulbTrue = stlMeshBody->isLightBulbOn(true);

    isLightBulbOn = stlMeshBody->isLightBulbOn();

    isVisible = stlMeshBody->isVisible();

    // Get and set mesh body Opacity
    bool isSetOpacityTrue = subComp->opacity(0.5);

    isSetOpacityTrue = stlMeshBody->opacity(0.6);

    double opacity = stlMeshBody->opacity();

    double visibleOpacity = meshBodyProxy->visibleOpacity();

    // Get and set mesh body material
    Ptr materialLibraries = app->materialLibraries();
    if (!materialLibraries)
        return false;

    Ptr materialLibrary = materialLibraries->itemByName("Fusion Material Library");
    if (!materialLibrary)
        return false;

    Ptr materials = materialLibrary->materials();
    if (!materials)
        return false;

    Ptr newMaterial = materials->itemByName("Glass, Bronze Glazing, Low E");
    if (!newMaterial)
        return false;

    bool isSetMaterialTrue = stlMeshBody->material(newMaterial);

    Ptr material = stlMeshBody->material();
    if (!material)
        return false;

    std::string materialName = material->name();

    // Get and set mesh body appearance
    Ptr appearanceLibrary = materialLibraries->itemByName("Fusion Appearance Library");
    if (!appearanceLibrary)
        return false;

    Ptr appearances = appearanceLibrary->appearances();
    if (!appearances)
        return false;

    Ptr newAppearance = appearances->itemByName("Glass - Window");
    if (!newAppearance)
        return false;

    bool isSetAppearanceTrue = stlMeshBody->appearance(newAppearance);

    Ptr appearance = stlMeshBody->appearance();
    if (!appearance)
        return false;

    std::string appearanceName = appearance->name();

    return true;
}

std::string getDllPath()
{
#if defined(_WINDOWS) || defined(_WIN32) || defined(_WIN64)
    HMODULE hModule = NULL;
    if (!GetModuleHandleExA(
            GET_MODULE_HANDLE_EX_FLAG_FROM_ADDRESS | GET_MODULE_HANDLE_EX_FLAG_UNCHANGED_REFCOUNT,
            (LPCSTR)&getDllPath,
            &hModule))
        return "";

    char winTempPath[2048];
    ::GetModuleFileNameA(hModule, winTempPath, 2048);

    std::string strPath = winTempPath;
    size_t stPos = strPath.rfind('\\');
    return strPath.substr(0, stPos);
#else
    Dl_info info;
    dladdr((void*)getDllPath, &info);

    std::string strPath = info.dli_fname;
    int stPos = (int)strPath.rfind('/');
    if (stPos != -1)
        return strPath.substr(0, stPos);
    else
        return "";
    ;
#endif
}
